// ── Agent Report Builder ──────────────────────────────────────────
// Formats an agent task completion report for Slack.
// In production, replace this node's input with actual agent output
// from the Ollama HTTP node or a sub-workflow.
//
// Expected input fields (from upstream nodes):
//   agent_name   : string — e.g. 'Jason'
//   task         : string — what was done
//   result       : string — output or summary
//   status       : 'success' | 'error' | 'partial'
//   duration_sec : number — how long it took

const input = $input.first().json;

const agent    = input.agent_name  || 'Unknown Agent';
const task     = input.task        || 'Unspecified task';
const result   = input.result      || 'No output';
const status   = input.status      || 'success';
const duration = input.duration_sec || 0;

const statusEmoji = {
  success : ':white_check_mark:',
  error   : ':x:',
  partial : ':warning:'
}[status] || ':grey_question:';

// Build Slack Block Kit message
const message = {
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: `${statusEmoji}  Agent Report — ${agent}`,
        emoji: true
      }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Task:*\n${task}` },
        { type: 'mrkdwn', text: `*Status:*\n${status.toUpperCase()}` },
        { type: 'mrkdwn', text: `*Agent:*\n${agent}` },
        { type: 'mrkdwn', text: `*Duration:*\n${duration}s` }
      ]
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Output:*\n\`\`\`${result.substring(0, 2800)}\`\`\``
      }
    },
    {
      type: 'context',
      elements: [
        {
          type: 'mrkdwn',
          text: `<!date^${Math.floor(Date.now()/1000)}^{date_short_pretty} at {time}|${new Date().toISOString()}>  ·  ai-workers`
        }
      ]
    }
  ]
};

return [{ json: { slackPayload: message } }];

// Log the result
const status = $input.first().json;
console.log('Slack response:', JSON.stringify(status));
return $input.all();
